// minimalProjectDir creates a project dir with a clean .ddx/config.yaml that
// has no agent.harness pin so flag values drive routing.
func minimalProjectDir(t *testing.T) string {
	t.Helper()
	dir := t.TempDir()
	t.Setenv("HOME", dir)
	ddxDir := filepath.Join(dir, ".ddx")
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	cfg := `version: "1.0"
library:
  path: ".ddx/plugins/ddx"
  repository:
    url: "https://example.com/lib"
    branch: "main"
`
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfg), 0o644))
	return dir
}

type blockingAgentRunner struct {
	started chan struct{}
	once    sync.Once
}

func (r *blockingAgentRunner) Run(opts agent.RunArgs) (*agent.Result, error) {
	r.once.Do(func() { close(r.started) })
	ctx := opts.Context
	if ctx == nil {
		ctx = context.Background()
	}
	<-ctx.Done()
	return &agent.Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
}

