110	func printProjectRuntimePreflightWarnings(w io.Writer, report ProjectRuntimePreflightReport) {
111		if w == nil || !report.Degraded() {
112			return
113		}
114		fmt.Fprintf(w, "preflight: project root: %s\n", report.ProjectRoot)
115		for _, issue := range report.Issues {
116			fmt.Fprintf(w, "preflight: %s\n", issue.Description)
117			for _, path := range issue.CheckedPaths {
118				fmt.Fprintf(w, "preflight: checked path: %s\n", path)
119			}
120			for _, remediation := range issue.Remediation {
121				fmt.Fprintf(w, "preflight: remediation: %s\n", remediation)
122			}
123		}
124	}
